import{_ as a,c as s,o as t,a5 as n}from"./chunks/framework.CgT1UzWm.js";const m=JSON.parse(`{"title":"Parameter Value Substitution","titleTemplate":"NpgsqlRest","description":"Use {name} placeholders in NpgsqlRest comment annotations to inject a request's parameter values into response headers, custom parameters, and HTTP custom type calls at request time.","frontmatter":{"outline":[2,3],"title":"Parameter Value Substitution","titleTemplate":"NpgsqlRest","description":"Use {name} placeholders in NpgsqlRest comment annotations to inject a request's parameter values into response headers, custom parameters, and HTTP custom type calls at request time.","head":[["meta",{"name":"keywords","content":"npgsqlrest parameter substitution, annotation placeholder, dynamic response header, dynamic content-type, parameter value placeholder, npgsqlrest {name}"}],["meta",{"property":"og:title","content":"NpgsqlRest Parameter Value Substitution"}],["meta",{"property":"og:description","content":"Inject request parameter values into annotation values with {name} placeholders."}],["meta",{"property":"og:type","content":"article"}],["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/annotations/parameter-substitution.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/annotations/parameter-substitution.html"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"NpgsqlRest Parameter Value Substitution"}],["meta",{"name":"twitter:description","content":"Inject request parameter values into annotation values with {name} placeholders."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"annotations/parameter-substitution.md","filePath":"annotations/parameter-substitution.md","lastUpdated":1782480183000}`),i={name:"annotations/parameter-substitution.md"};function r(l,e,o,p,d,h){return t(),s("div",null,e[0]||(e[0]=[n(`<h1 id="parameter-value-substitution" tabindex="-1">Parameter Value Substitution <a class="header-anchor" href="#parameter-value-substitution" aria-label="Permalink to &quot;Parameter Value Substitution&quot;">​</a></h1><p>Several comment annotations accept a <strong><code>{name}</code> placeholder</strong> in their value. At <strong>request time</strong>, <code>{name}</code> is replaced with the value of the routine parameter <code>name</code> taken from that request. This lets a single endpoint produce a response header, file name, upload path, or outbound HTTP call that depends on what the caller sent.</p><p>This is one shared mechanism reused by a few annotations — this page documents it once; each annotation page links here.</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">create</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> function</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> export_report</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">(_type </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">text</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">, _file </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">text</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">)</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">returns</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> text</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> language</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> sql</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> as</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> $$ </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">select</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;...report...&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> $$;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function export_report(text, text) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">Content-Type: {_type}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">Content-Disposition: attachment; filename={_file}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div></details><p>A request <code>GET /api/export-report?type=text/csv&amp;file=q1.csv</code> responds with <code>Content-Type: text/csv</code> and <code>Content-Disposition: attachment; filename=q1.csv</code>.</p><h2 id="where-it-works" tabindex="-1">Where it works <a class="header-anchor" href="#where-it-works" aria-label="Permalink to &quot;Where it works&quot;">​</a></h2><p><code>{name}</code> substitution is applied to these annotation values:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Annotation</th><th>What is substituted</th><th>Page</th></tr></thead><tbody><tr><td><strong>Response headers</strong> (<code>Header-Name: value</code>), including <code>Content-Type</code></td><td>the header value</td><td><a href="./response-headers.html">Response Headers</a></td></tr><tr><td><strong>Custom parameters</strong> (<code>@key = value</code>) — e.g. upload paths/filenames</td><td>the value after <code>=</code></td><td><a href="./custom-parameters.html">Custom Parameters</a></td></tr><tr><td><strong>HTTP custom types</strong> — request URL, query string, headers, and body</td><td>those parts of the outbound call</td><td><a href="./http-type.html">HTTP Custom Types</a></td></tr></tbody></table></div></div><p>Other annotations do <strong>not</strong> perform this substitution. (Braces in unrelated annotations — e.g. a URL <code>{segment}</code> in <a href="./path.html"><code>PATH</code></a> — are a different feature; see <a href="#not-to-be-confused-with">Not to be confused with</a>.)</p><h2 id="how-a-placeholder-is-resolved" tabindex="-1">How a placeholder is resolved <a class="header-anchor" href="#how-a-placeholder-is-resolved" aria-label="Permalink to &quot;How a placeholder is resolved&quot;">​</a></h2><p>For each request, NpgsqlRest builds a lookup from the bound parameters (plus any <a href="#environment-variables">allowlisted environment variables</a>) and replaces every <code>{name}</code> it finds:</p><ul><li><strong>The name is matched case-insensitively.</strong> <code>{userId}</code>, <code>{USERID}</code>, and <code>{userid}</code> all resolve the same parameter. (Consistent with how PostgreSQL folds unquoted identifiers, and with <a href="#not-to-be-confused-with">resolved parameter expressions</a>.)</li><li><strong>Both names work.</strong> A placeholder matches either the <strong>original PostgreSQL parameter name</strong> (e.g. <code>{_user_id}</code>) <strong>or</strong> its <strong>converted (camelCase) name</strong> (e.g. <code>{userId}</code>). For <a href="./http-type.html">HTTP custom types</a>, the <strong>type field name</strong> also matches.</li><li><strong>NULL or a missing value → empty string.</strong> If the parameter is SQL <code>NULL</code> (or not supplied), <code>{name}</code> becomes \`\` (nothing).</li><li><strong>An unknown name is left untouched — and warned about.</strong> If <code>name</code> matches no parameter, the literal text <code>{name}</code> is kept verbatim in the output, <em>and</em> NpgsqlRest logs a <strong>build-time warning</strong> naming the placeholder, so typos (e.g. <code>{_fil}</code> for <code>{_file}</code>) surface at startup instead of silently shipping literal text. (The warning only fires for response headers and custom parameters, and only when the placeholder looks like an identifier — <code>{0}</code> or JSON-like <code>{&quot;a&quot;:1}</code> are never treated as placeholders.)</li><li><strong>Substitution is per-request</strong>, evaluated against the actual values bound for that call — not fixed when the endpoint is created.</li><li><strong>Zero overhead when unused.</strong> A value is only scanned when it actually contains braces, so endpoints without placeholders pay nothing.</li></ul><h3 id="brace-handling" tabindex="-1">Brace handling <a class="header-anchor" href="#brace-handling" aria-label="Permalink to &quot;Brace handling&quot;">​</a></h3><ul><li>There is <strong>no escape sequence</strong> for a literal brace. A <code>{...}</code> whose inner text doesn&#39;t match a parameter is simply passed through unchanged (so <code>{not_a_param}</code> survives literally), but you cannot force a literal <code>{userId}</code> when <code>userId</code> <em>is</em> a parameter.</li><li>A stray <code>}</code> with no opening <code>{</code>, and an unclosed <code>{</code>, are passed through as-is.</li></ul><h2 id="environment-variables" tabindex="-1">Environment variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment variables&quot;">​</a></h2><p>A <code>{name}</code> can also resolve to an <strong>environment variable</strong> — useful for outbound API keys (HTTP custom types) or per-deployment values like a server/environment name in a response header — without routing them through request parameters.</p><p>This is <strong>opt-in via an allowlist</strong>: only environment variables you name in <code>NpgsqlRest:AvailableEnvVars</code> can be referenced. Any other <code>{NAME}</code> is never read from the environment (it stays literal, like an unknown parameter). The allowlist is the security boundary — there is no way to substitute an arbitrary env var.</p><details class="code-collapsible" open><summary>jsonc</summary><div class="language-jsonc vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">{</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">NpgsqlRest</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">    // array form — a missing variable resolves to an empty string</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">    &quot;</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">AvailableEnvVars</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> [</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;WEATHER_API_KEY&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &quot;SERVER_NAME&quot;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> ]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">    // …or object form — name → default used when the variable is absent</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">    // &quot;AvailableEnvVars&quot;: { &quot;SERVER_NAME&quot;: &quot;local&quot; }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></details><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on type weather_api is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">GET https://api.example.com/v1/current?city={_city}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">Authorization: Bearer {WEATHER_API_KEY}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><p>Here <code>{_city}</code> comes from a request parameter and <code>{WEATHER_API_KEY}</code> from the allowlisted environment variable — the API key never has to be passed by the caller.</p><p>Rules specific to env vars:</p><ul><li><strong>Resolved once at startup.</strong> The process environment is read when the app starts; changing a variable requires a restart (e.g. a new pod).</li><li><strong>Case-insensitive</strong>, same as parameters (<code>{server_name}</code> resolves <code>SERVER_NAME</code>).</li><li><strong>A routine parameter of the same name wins.</strong> If a request parameter and an allowlisted env var share a name, the parameter value is used.</li><li><strong>Allowlisted names don&#39;t trigger the typo warning</strong> — they&#39;re recognized placeholders.</li></ul><p>Since 3.21.0, the strict forms from <a href="/config/config-section.html#placeholder-forms-optional-required-and-fallback-3-17-0-fallback-3-20-1">configuration placeholders</a> work here too, with the same grammar:</p><ul><li><code>{!NAME}</code> — resolves like <code>{NAME}</code> for allowlisted names (and parameters).</li><li><code>{!NAME:fallback}</code> — resolves to the value; when the allowlisted variable is unset and has no configured default, the literal <code>fallback</code> text is used instead. Also applies to parameters: a <strong>null parameter value yields the fallback</strong> (<code>X-Plan: {!_plan:free}</code> sends <code>free</code> when <code>_plan</code> is null).</li><li>Unlisted names stay literal in every form — the strict forms never widen the allowlist.</li></ul><div class="warning custom-block"><p class="custom-block-title">Response headers are client-visible</p><p>A value substituted into a <strong>response header</strong> is sent to the caller. That&#39;s exactly what you want for a per-pod <code>Server: {SERVER_NAME}</code> header, but it means you must <strong>not</strong> put a secret env var in a response header. Reserve secrets (API keys, tokens) for outbound <a href="./http-type.html">HTTP custom type</a> calls and <a href="./custom-parameters.html">custom parameters</a>, which stay server-side.</p></div><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><h3 id="dynamic-file-download" tabindex="-1">Dynamic file download <a class="header-anchor" href="#dynamic-file-download" aria-label="Permalink to &quot;Dynamic file download&quot;">​</a></h3><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function get_invoice(_id int, _filename text) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">Content-Type: application/pdf</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">Content-Disposition: attachment; filename={_filename}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><h3 id="upload-destination-from-a-parameter" tabindex="-1">Upload destination from a parameter <a class="header-anchor" href="#upload-destination-from-a-parameter" aria-label="Permalink to &quot;Upload destination from a parameter&quot;">​</a></h3><p>See <a href="./custom-parameters.html">Custom Parameters</a> and <a href="./upload.html">Upload</a>. The upload handler&#39;s path/filename keys accept placeholders:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function upload_avatar(_user_id int, _path text) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@upload for file_system</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@file_system_path = /var/uploads/{_user_id}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><h3 id="outbound-http-call-shaped-by-parameters" tabindex="-1">Outbound HTTP call shaped by parameters <a class="header-anchor" href="#outbound-http-call-shaped-by-parameters" aria-label="Permalink to &quot;Outbound HTTP call shaped by parameters&quot;">​</a></h3><p>See <a href="./http-type.html">HTTP Custom Types</a>. The URL, headers, and body of the proxied call accept placeholders — mix request parameters with an allowlisted <a href="#environment-variables">environment variable</a> so the API key never has to be passed by the caller:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on type weather_api is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">GET https://api.example.com/v1/current?city={_city}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">Authorization: Bearer {WEATHER_API_KEY}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><h2 id="not-to-be-confused-with" tabindex="-1">Not to be confused with <a class="header-anchor" href="#not-to-be-confused-with" aria-label="Permalink to &quot;Not to be confused with&quot;">​</a></h2><p>NpgsqlRest uses <code>{...}</code> syntax in a few unrelated places. They are different features with different rules:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Feature</th><th>Looks like</th><th>When/where</th><th>Rules</th></tr></thead><tbody><tr><td><strong>Parameter value substitution</strong> (this page)</td><td><code>{name}</code> in an annotation value</td><td>request time, into headers / custom params / HTTP-type calls</td><td>case-<strong>insensitive</strong>; unknown → literal (+ build-time warning); NULL → empty</td></tr><tr><td><a href="./../config/config-section.html">Environment-variable config placeholders</a></td><td><code>{NAME}</code> / <code>{!NAME}</code> in <code>appsettings.json</code></td><td>startup, into config values</td><td>resolved from env vars; <code>{!NAME}</code> errors if unset</td></tr><tr><td><a href="./path.html">URL path segments</a></td><td><code>{segment}</code> in a <code>PATH</code> route</td><td>routing</td><td>maps a URL path segment to a parameter</td></tr><tr><td><a href="./resolved-parameters.html">Resolved parameter expressions</a></td><td><code>param = &lt;sql&gt;</code> (may itself contain <code>{name}</code>)</td><td>request time, <strong>server-side in SQL</strong></td><td>the parameter is computed by running SQL; its result then substitutes here. <code>{name}</code> inside that SQL is matched case-<strong>insensitively</strong> (same as this page)</td></tr></tbody></table></div></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./response-headers.html">Response Headers</a> - dynamic headers and <code>Content-Type</code></li><li><a href="./custom-parameters.html">Custom Parameters</a> - <code>@key = value</code> handler parameters</li><li><a href="./resolved-parameters.html">Resolved Parameters</a> - compute a <code>{name}</code> value server-side from SQL (DB-stored tokens, secrets)</li><li><a href="./http-type.html">HTTP Custom Types</a> - placeholders in proxied URL / headers / body</li><li><a href="./../guide/annotations.html">Comment Annotations Guide</a> - how annotations work</li></ul>`,39)]))}const u=a(i,[["render",r]]);export{m as __pageData,u as default};
